    public String createSelect(String title, String id, int selectedField, List<CellInfo> fields) {
        StringBuilder sb = new StringBuilder();
        sb.append("<select title='"+title+"' data-title='" + title + "' id='" + id + "'>");
        sb.append("<option value='-1'></option>");

        for(CellInfo info: fields) {
            if(info==null) continue;
            int domainId = info.getDomainId();
            sb.append("<option");
            sb.append(" value='").append(domainId).append("'");
            if(selectedField != -1 && selectedField == domainId) sb.append("selected");
            sb.append(">").append(info.getValue()).append("</option>");
        }
        sb.append("</select>");
        return sb.toString();
    }
