    public String createAvailableTimesSelect( RagicBundle bundle,JSONObject start, JSONObject end, int timezoneHoursOffset) {
        StringBuilder sb = new StringBuilder();
        sb.append("<div class='timeSection'>");
        sb.append("<select title='"+bundle.getString("accessibility_startTime")+"' onchange='availableTimesChange(this)'>");
        for(int i = 0; i < 25; i++) {
            String hour = (i < 10 ? "0" : "") + i;
            boolean isHour = start != null && i == start.optInt("hour") + timezoneHoursOffset;
            int minute =  start != null ? start.optInt("minute") : -1;
            sb.append("<option style='background-color: #d4d4d4;' value='" + hour + ":00'" + (isHour && 0 == minute ? "selected" : "") + ">" + (hour + ":00") + "</option>");
            if(i < 24) {
                sb.append("<option value='" + hour + ":15'" + (isHour && 15 == minute ? "selected" : "") + ">" + (hour + ":15") + "</option>");
                sb.append("<option value='" + hour + ":30'" + (isHour && 30 == minute ? "selected" : "") + ">" + (hour + ":30") + "</option>");
                sb.append("<option value='" + hour + ":45'" + (isHour && 45 == minute ? "selected" : "") + ">" + (hour + ":45") + "</option>");
            }
        }

        sb.append("</select>");
        sb.append("<span style='margin: 0 20px; font-weight: 700;'>-</span>");
        sb.append("<select title='"+bundle.getString("accessibility_endTime")+"' onchange='availableTimesChange(this)'>");
        for(int i = 0; i < 25; i++) {
            String hour = (i < 10 ? "0" : "") + i;
            boolean isHour = end != null && i == end.optInt("hour") + timezoneHoursOffset;
            int minute = end != null ? end.optInt("minute") : -1;
            sb.append("<option style='background-color: #d4d4d4;' value='" + hour + ":00'" + (isHour && 0 == minute ? "selected" : "") + ">" + (hour + ":00") + "</option>");
            if(i < 24) {
                sb.append("<option value='" + hour + ":15'" + (isHour && 15 == minute ? "selected" : "") + ">" + (hour + ":15") + "</option>");
                sb.append("<option value='" + hour + ":30'" + (isHour && 30 == minute ? "selected" : "") + ">" + (hour + ":30") + "</option>");
                sb.append("<option value='" + hour + ":45'" + (isHour && 45 == minute ? "selected" : "") + ">" + (hour + ":45") + "</option>");
            }
        }
        sb.append("</select>");
        sb.append("<span class='availableTimes-error'></span>");
        sb.append("</div>");

        return sb.toString();
    }

