    private boolean detectTimeOverLap(DateTimeFormatter df, String target, String startTime, String endTime,Map<String, List<AbstractMap.SimpleEntry<LocalDateTime,LocalDateTime>>> reservedList) {
        LocalDateTime start = LocalDateTime.parse(startTime, df);
        LocalDateTime end = LocalDateTime.parse(endTime, df);
        boolean conflicted = false;

        List<AbstractMap.SimpleEntry<LocalDateTime,LocalDateTime>> timeList = reservedList.get(target);
        if(timeList != null) {
            List<AbstractMap.SimpleEntry<LocalDateTime,LocalDateTime>> newTimeList = new ArrayList<>();
            for(Map.Entry<LocalDateTime, LocalDateTime> e : timeList) {
                LocalDateTime otherStart = e.getKey(),
                        otherEnd = e.getValue();

                if(!(start.isBefore(otherStart) && (end.isEqual(otherStart) || end.isBefore(otherStart)) ||
                        otherStart.isBefore(start) && (otherEnd.isEqual(start) || otherEnd.isBefore(start)))) {
                    if(!hasConflictedTime) hasConflictedTime = true;
                    conflicted = true;
                    break;
                }
            }

            if(conflicted) {
                return true;
            }
            else {
                newTimeList.add(new AbstractMap.SimpleEntry<>(start, end));
            }

            timeList.addAll(newTimeList);
        }
        else {
            timeList = new ArrayList<>();
            timeList.add(new AbstractMap.SimpleEntry<>(start, end));
            reservedList.put(target, timeList);
        }
        return false;
    }
    private Map<String, Boolean> processUserRight(int right, BDBWorker worker, User user, NUIForm form, int rootNodeId) {
        Map<String, Boolean> map = new HashMap<>();

        switch (right) {
            //We don't do this since if user is no right, then he cannot see this report
//                case Const.NORIGHT:
//                    map.put("canView", false);
//                    map.put("canCreate", false);
//                    map.put("canEdit", false);
//                    return map;
            case Const.USER:
                boolean ifHasRightInUSER = worker.checkAccessToNode(form.getRootDomainId(), rootNodeId, user);
                map.put("canView", ifHasRightInUSER);
                map.put("canEdit", ifHasRightInUSER && !form.ifUserNoEdit(user));
                break;
            case Const.VIEWER:
                map.put("canView", true);
                map.put("canEdit", false);
                break;
            case Const.MANAGER:
                boolean ifHasRightInMANAGER = worker.checkAccessToNode(form.getRootDomainId(), rootNodeId, user);
                map.put("canView", true);
                map.put("canEdit", ifHasRightInMANAGER && !form.ifUserNoEdit(user));
                break;
            case Const.ADMIN:
                map.put("canView", true);
                map.put("canEdit", true);
                break;
        }

        return map;
    }

    private boolean canCreateData(int right, User user, NUIForm form) {
        switch (right) {
            //We don't do this since if user is no right, then he cannot see this report
//            case Const.NORIGHT:
//                return false;
            case Const.USER:
                return !form.ifUserNoCreate(user);
            case Const.VIEWER:
                return false;
            case Const.MANAGER:
                return !form.ifUserNoCreate(user);
            case Const.ADMIN:
                return true;
            default:
                return false;
        }
    }

